import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { theme, Row, Col, Card, Space, Typography, Select, DatePicker, Button, Table, Progress, Tag, App, Breadcrumb, Flex } from "antd";
import { 
  BarChartOutlined, PieChartOutlined, 
  SearchOutlined, DownloadOutlined,
  SafetyCertificateOutlined, InfoCircleOutlined, HomeOutlined
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import ExcelJS from "exceljs";
import dayjs from "dayjs";

const { useToken } = theme;
const { Title, Text } = Typography;
const { RangePicker } = DatePicker;

// --- Realistic Mock Data (Sync with labeling:panel.reasons) ---
const mockDefectKeys = [
  { key: "1", reasonKey: "wrong_class", count: 120, rate: 35 },
  { key: "2", reasonKey: "missed_object", count: 85, rate: 25 },
  { key: "3", reasonKey: "loose_tightness", count: 65, rate: 19 },
  { key: "4", reasonKey: "missed_point", count: 42, rate: 12 },
  { key: "5", reasonKey: "duplicate", count: 30, rate: 9 },
];

const mockProjectStats = [
  { key: "1", prjNm: "자율주행 - 도심 도로 주행 데이터", workCnt: 446, errorRate: 1.25 },
  { key: "2", prjNm: "CCTV 지능형 안전 통합 관제", workCnt: 1200, errorRate: 2.84 },
  { key: "3", prjNm: "의료 영상 판독용 AI 데이터셋", workCnt: 8500, errorRate: 1.52 },
  { key: "4", prjNm: "스마트 팩토리 안전화 인식", workCnt: 88, errorRate: 0.92 },
];

export default function StatDefectPage() {
  const { token } = useToken();
  const { t } = useTranslation(["stats", "common", "project", "labeling"]);
  const { message } = App.useApp();

  const [dateRange, setDateRange] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const handleSearch = () => {
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      message.success(t("confirm", { ns: "common" }));
    }, 400);
  };

  const handleExport = async () => {
    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet("Defects");
    worksheet.columns = [
      { header: t("defect.reason"), key: "r", width: 30 },
      { header: t("defect.count"), key: "c", width: 15 }
    ];
    mockDefectKeys.forEach(d => worksheet.addRow({ r: t(`panel.reasons.${d.reasonKey}`, { ns: "labeling" }), c: d.count }));
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
    const link = document.createElement("a");
    link.href = window.URL.createObjectURL(blob);
    link.download = `DefectStats_${dayjs().format("YYYYMMDD")}.xlsx`;
    link.click();
    message.success(t("msg.exportDone", { ns: "project" }));
  };

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("tabs.defect")}</Title>
        </div>
        <Flex vertical align="flex-end" gap={8}>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
              { title: t("title") },
              { title: t("tabs.defect") }
            ]} 
          />
          <Space>
            <RangePicker size="small" value={dateRange} onChange={setDateRange} />
            <Button type="primary" size="small" icon={<SearchOutlined />} onClick={handleSearch} loading={loading}>{t("search", { ns: "common" })}</Button>
            <Button size="small" icon={<DownloadOutlined />} onClick={handleExport}>{t("export", { ns: "project" })}</Button>
          </Space>
        </Flex>
      </div>

      <Row gutter={16}>
        <Col span={14}>
          <Card 
            title={<Space><BarChartOutlined /> {t("defect.reasonRanking")}</Space>} 
            variant="borderless" 
            style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary, height: 450, background: token.colorBgContainer }}
          >
            <ReactECharts 
              option={{
                xAxis: { type: 'value' },
                yAxis: { type: 'category', data: mockDefectKeys.map(d => t(`panel.reasons.${d.reasonKey}`, { ns: "labeling" })).reverse() },
                series: [{ type: 'bar', data: mockDefectKeys.map(d => d.count).reverse(), itemStyle: { color: token.colorError, borderRadius: [0, 8, 8, 0] } }]
              }} 
              style={{ height: 350 }} 
            />
          </Card>
        </Col>
        <Col span={10}>
          <Card 
            title={<Space><PieChartOutlined /> {t("defect.reasonRatio")}</Space>} 
            variant="borderless" 
            style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary, height: 450 }}
            styles={{ body: { padding: 0 } }}
          >
            <Table 
              size="small" dataSource={mockDefectKeys} pagination={false}
              columns={[
                { title: t("defect.reason"), dataIndex: "reasonKey", render: (v) => t(`panel.reasons.${v}`, { ns: "labeling" }) },
                { title: t("defect.count"), dataIndex: "count", align: "right" },
                { title: t("defect.ratio"), dataIndex: "rate", align: "right", render: (v) => `${v}%` },
              ]}
            />
          </Card>
        </Col>
      </Row>

      <Card 
        title={<Space><SafetyCertificateOutlined /> {t("defect.projectStats")}</Space>} 
        variant="borderless" style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary, marginTop: 16 }} styles={{ body: { padding: 0 } }}
      >
        <Table 
          size="small" dataSource={mockProjectStats} pagination={false}
          columns={[
            { title: t("modal.prjNm", { ns: "project" }), dataIndex: "prjNm" },
            { title: t("columns.workCount", { ns: "project" }), dataIndex: "workCnt", align: "right" },
            { title: t("summary.errorRate", { ns: "dashboard" }), dataIndex: "errorRate", align: "right", render: (v) => <Tag color="error">{v}%</Tag> },
            { title: t("progress", { ns: "project" }), align: "center", render: () => <Tag color="success">{t("statusDone", { ns: "labeling" })}</Tag> }
          ]}
        />
      </Card>
    </div>
  );
}
